import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[] a = new long[N];
            for (int i = 0; i < N; i++) a[i] = fs.nextLong();
            Arrays.sort(a);
            int maxf = 1, cur = 1;
            for (int i = 1; i < N; i++) {
                if (a[i] == a[i - 1]) cur++; else { maxf = Math.max(maxf, cur); cur = 1; }
            }
            maxf = Math.max(maxf, cur);
            if (maxf > N / 2) {
                out.append("NO\n");
                continue;
            }
            out.append("YES\n");
            for (int i = 0; i < N; i++) out.append(a[i]).append(i + 1 == N ? '\n' : ' ');
            int shift = N / 2;
            for (int i = 0; i < N; i++) out.append(a[(i + shift) % N]).append(i + 1 == N ? '\n' : ' ');
        }
        System.out.print(out.toString());
    }
    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false; if (c == '-') { neg = true; c = readByte(); }
            long val = 0; while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return neg ? -val : val; }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

