const fs = require('fs');
const data = fs.readFileSync(0, 'utf8').trim().split(/\s+/);
let idx = 0;
const T = Number(data[idx++]);
let out = [];
for (let tc = 0; tc < T; tc++) {
  const N = Number(data[idx++]);
  let arr = new Array(N);
  for (let i = 0; i < N; i++) arr[i] = Number(data[idx++]);
  arr.sort((a, b) => a - b);
  // max frequency
  let maxf = 1, cur = 1;
  for (let i = 1; i < N; i++) {
    if (arr[i] === arr[i - 1]) cur++; else { if (cur > maxf) maxf = cur; cur = 1; }
  }
  if (cur > maxf) maxf = cur;
  if (maxf > Math.floor(N / 2)) {
    out.push('NO');
    continue;
  }
  out.push('YES');
  out.push(arr.join(' '));
  const shift = Math.floor(N / 2);
  const c = [];
  for (let i = 0; i < N; i++) c.push(arr[(i + shift) % N]);
  out.push(c.join(' '));
}
console.log(out.join('\n'));

